'use client';

import { useAuth } from '../context/AuthContext';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { 
  Home, 
  Film, 
  Book, 
  Music, 
  GraduationCap, 
  ShoppingBag, 
  User as UserIcon, 
  Settings as SettingsIcon,
  LogOut,
  LogIn,
  UserPlus
} from 'lucide-react';

export function Sidebar() {
  const { user, logout } = useAuth();
  const pathname = usePathname();

  const navItems = [
    { name: 'All', href: '/', icon: Home },
    { name: 'Movies', href: '/movies', icon: Film },
    { name: 'Books', href: '/books', icon: Book },
    { name: 'Songs', href: '/songs', icon: Music },
    { name: 'Courses', href: '/courses', icon: GraduationCap },
    { name: 'Products', href: '/products', icon: ShoppingBag },
  ];

  const bottomItems = [
    { name: 'Profile', href: '/profile', icon: UserIcon },
    { name: 'Settings', href: '/settings', icon: SettingsIcon },
  ];

  const NavLink = ({ item }: { item: typeof navItems[0] }) => {
    const isActive = pathname === item.href;
    return (
      <Link 
        href={item.href} 
        className={`flex items-center gap-3 px-4 py-2.5 rounded-xl transition-all duration-200 group ${
          isActive 
            ? 'bg-indigo-600/20 text-white shadow-[0_0_15px_rgba(79,70,229,0.1)]' 
            : 'text-gray-400 hover:text-white hover:bg-white/5'
        }`}
      >
        <item.icon size={20} className={`${isActive ? 'text-indigo-400' : 'text-gray-500 group-hover:text-gray-300'}`} />
        <span className="font-medium">{item.name}</span>
        {isActive && (
          <div className="ml-auto w-1.5 h-1.5 rounded-full bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,0.8)]" />
        )}
      </Link>
    );
  };

  return (
    <aside className="sidebar">
      <div className="sidebar-logo">
        <img src="/logo.png" alt="VibeFlow" className="w-10 h-10 object-contain rounded-xl" />
        <span>VibeFlow</span>
      </div>
      
      <nav className="sidebar-nav">
        <div className="space-y-1">
          {navItems.map((item) => (
            <NavLink key={item.href} item={item} />
          ))}
        </div>
        
        <div className="my-6 border-t border-white/5" />
        
        <div className="space-y-1">
          {bottomItems.map((item) => (
            <NavLink key={item.href} item={item} />
          ))}
        </div>
      </nav>
      
      <div className="mt-auto pt-6 border-t border-white/5">
        {user ? (
          <div className="space-y-4">
            <div className="px-4">
              <p className="text-[10px] uppercase tracking-wider text-gray-500 font-bold mb-1">Signed in as</p>
              <p className="text-sm text-gray-300 truncate font-medium">{user.email}</p>
            </div>
            <button 
              onClick={logout}
              className="w-full flex items-center gap-3 px-4 py-2.5 text-red-400 hover:text-red-300 hover:bg-red-500/5 rounded-xl transition-all duration-200"
            >
              <LogOut size={20} />
              <span className="font-medium text-sm">Sign Out</span>
            </button>
          </div>
        ) : (
          <div className="space-y-2">
            <Link 
              href="/login" 
              className="flex items-center gap-3 px-4 py-2.5 text-gray-300 hover:text-white hover:bg-white/5 rounded-xl transition-all"
            >
              <LogIn size={20} />
              <span className="font-medium">Log In</span>
            </Link>
            <Link 
              href="/signup" 
              className="flex items-center gap-3 px-4 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl transition-all shadow-lg shadow-indigo-600/20"
            >
              <UserPlus size={20} />
              <span className="font-medium">Sign Up</span>
            </Link>
          </div>
        )}
      </div>
    </aside>
  );
}
